using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  auto conn = sqlgen::sqlite::connect(db_path).value();

  for (const auto& record : records) {
    sqlgen::insert(conn, record).value();
  }
}

template<typename T>
void modify_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id,
                               const std::string& col_name,
                               const T& new_value) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        std::string pk_column;
        if (table_name == "Student") pk_column = "SNo";
        else if (table_name == "Course") pk_column = "CID";
        else if (table_name == "Score") pk_column = "ScID";
        else if (table_name == "Major") pk_column = "MID";

        std::string sql = "UPDATE " + table_name + " SET " + col_name + " = ? WHERE " + pk_column + " = ?";
        return sqlgen::exec(conn, sql, new_value, record_id);
      })
      .value();
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  sqlgen::sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        std::string pk_column;
        if (table_name == "Student") pk_column = "SNo";
        else if (table_name == "Course") pk_column = "CID";
        else if (table_name == "Score") pk_column = "ScID";
        else if (table_name == "Major") pk_column = "MID";

        std::string sql = "DELETE FROM " + table_name + " WHERE " + pk_column + " = ?";
        return sqlgen::exec(conn, sql, record_id);
      })
      .value();
}
```

**Key implementation details:**

1. **`add_eas_records`**: 
   - Connects to the SQLite database using `sqlgen::sqlite::connect`
   - Iterates through all records and inserts each one using `sqlgen::insert`
   - Template parameter `T` allows it to work with any table structure (Student, Course, Score, Major)

2. **`modify_eas_records_by_id`** (added function):
   - Determines the primary key column name based on the table name
   - Constructs an UPDATE SQL statement with placeholders
   - Uses `sqlgen::exec` with parameterized query to prevent SQL injection
   - Template parameter `T` for new_value allows flexibility in data types

3. **`delete_eas_records_by_id`**:
   - Maps table names to their respective primary key column names
   - Constructs a DELETE SQL statement with a WHERE clause
   - Uses parameterized queries for safe execution
   - Accepts record_id as string for flexibility across different primary key types

