  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Define the Employee table
    auto employee_table = sqlgen::define_table<Employee>("Employee");

    // Create aliases for self-join (e1 for employee, e2 for manager)
    auto e1 = employee_table.as("e1");
    auto e2 = employee_table.as("e2");

    // Build the query with LEFT JOIN
    // SELECT e1.name as employee, e2.name as manager
    // FROM Employee e1
    // LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id
    auto query = sqlgen::select(e1.name.as("employee"), e2.name.as("manager"))
                    .from(e1)
                    .left_join(e2).on(e1.manager_id == e2.emp_id);

    // Execute the query and collect results
    std::vector<EmployeeManager> results;
    auto result_set = db.execute(query);

    for (auto& row : result_set) {
        EmployeeManager em;
        em.employee = row.get<std::string>("employee");
        em.manager = row.get<std::optional<std::string>>("manager");
        results.push_back(em);
    }

    return results;
}

}  // namespace query_employee_hierarchy

