struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Connect to SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Start with base SELECT query
    auto query = sqlgen::select<Book>();

    // Add WHERE clauses dynamically based on provided filters

    // Title keyword search using LIKE
    if (filters.title_keyword) {
        std::string pattern = "%" + *filters.title_keyword + "%";
        query = query.where(sqlgen::like(&Book::title, pattern));
    }

    // Minimum year filter (year >= min_year)
    if (filters.min_year) {
        query = query.where(sqlgen::gte(&Book::year, *filters.min_year));
    }

    // Genre exact match
    if (filters.genre) {
        query = query.where(sqlgen::eq(&Book::genre, *filters.genre));
    }

    // Maximum price filter (price <= max_price)
    if (filters.max_price) {
        query = query.where(sqlgen::lte(&Book::price, *filters.max_price));
    }

    // Execute query and return results
    return db.execute(query);
}

}  // namespace query_search_books_by_criteria

