namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  try {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::open("test_db.sqlite");

    // Start a transaction
    db.exec("BEGIN TRANSACTION");

    // Check if the sender has sufficient funds
    auto from_account = db.select<Account>()
                          .where("account_id = ?", from_account_id)
                          .one();

    if (!from_account || from_account->balance < amount) {
      db.exec("ROLLBACK");
      return false;
    }

    // Deduct amount from sender's account
    auto rows_updated = db.exec(
      "UPDATE Account SET balance = balance - ? WHERE account_id = ? AND balance >= ?",
      amount, from_account_id, amount
    );

    if (rows_updated == 0) {
      db.exec("ROLLBACK");
      return false;
    }

    // Add amount to receiver's account
    db.exec(
      "UPDATE Account SET balance = balance + ? WHERE account_id = ?",
      amount, to_account_id
    );

    // Commit the transaction
    db.exec("COMMIT");

    return true;
  } catch (...) {
    // Rollback on any exception
    try {
      auto db = sqlgen::sqlite::open("test_db.sqlite");
      db.exec("ROLLBACK");
    } catch (...) {}
    return false;
  }
}

