 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  // Connect to the SQLite database
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // SQLite doesn't support RIGHT JOIN directly, so we simulate it using LEFT JOIN
  // To demonstrate RIGHT JOIN behavior that includes all departments,
  // we perform: Department LEFT JOIN Project
  // This ensures all departments are included, even those without projects
  // 
  // Note: Based on the result structure, we map:
  // - department_name (optional, for departments that might not match)
  // - project_name (required, from all projects)
  auto query = "SELECT d.name as department_name, p.name as project_name "
               "FROM Department d "
               "LEFT JOIN Project p ON d.department_id = p.department_id";

  // Execute the query and return results mapped to DepProj structs
  return db.read<DepProj>(query);
}

}  // namespace right_join_departments_projects
```

**Note**: SQLite doesn't natively support RIGHT JOIN, so this implementation uses LEFT JOIN with `Department` as the left table to achieve the equivalent behavior. This ensures all departments are included in the results, with `project_name` being populated when a matching project exists. The query returns all departments, even those without associated projects (where project fields would be NULL, mapped to `std::optional` in the result structure).

