    SELECT 
      product_id,
      name,
      ABS(price) as abs_price,
      CAST(CEIL(price) AS REAL) as ceil_price,
      CAST(FLOOR(price) AS REAL) as floor_price,
      ROUND(price, 2) as rounded_price,
      EXP(discount_rate/100.0) as exp_discount,
      LN(price) as ln_price,
      LOG2(quantity) as log2_quantity,
      SIN(discount_rate) as sin_discount,
      COS(discount_rate) as cos_discount,
      TAN(discount_rate) as tan_discount,
      SQRT(quantity) as sqrt_quantity
    FROM Product
  )");

  // Fetch and return results
  std::vector<MathAnalysis> results;

  while (query_stmt.step()) {
    MathAnalysis analysis;
    analysis.product_id = query_stmt.column_int(0);
    analysis.name = query_stmt.column_text(1);
    analysis.abs_price = query_stmt.column_double(2);
    analysis.ceil_price = query_stmt.column_double(3);
    analysis.floor_price = query_stmt.column_double(4);
    analysis.rounded_price = query_stmt.column_double(5);
    analysis.exp_discount = query_stmt.column_double(6);
    analysis.ln_price = query_stmt.column_double(7);
    analysis.log2_quantity = query_stmt.column_double(8);
    analysis.sin_discount = query_stmt.column_double(9);
    analysis.cos_discount = query_stmt.column_double(10);
    analysis.tan_discount = query_stmt.column_double(11);
    analysis.sqrt_quantity = query_stmt.column_double(12);

    results.push_back(analysis);
  }

  return results;
}

}  // namespace mathematical_operations_analysis

