```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  std::vector<SupProd> results;

  // SQLite doesn't support FULL OUTER JOIN natively
  // Simulate it by combining a LEFT JOIN with a query for unmatched products

  std::string query = R"(
    SELECT s.name AS supplier_name, p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT NULL AS supplier_name, p.name AS product_name
    FROM Product p
    WHERE p.supplier_id NOT IN (SELECT supplier_id FROM Supplier)
  )";

  auto stmt = conn.prepare(query);
  while (stmt.step()) {
    SupProd row;
    row.supplier_name = stmt.column<std::string>(0);
    row.product_name = stmt.column<std::optional<std::string>>(1);
    results.push_back(row);
  }

  return results;
}

} // namespace full_join_suppliers_products
