  std::vector<SupProd> results;

  // SQLite doesn't natively support FULL OUTER JOIN
  // Simulate FULL JOIN using UNION of LEFT JOIN and RIGHT JOIN equivalent
  // LEFT JOIN: all suppliers with their products (NULL if no product)
  // UNION: all products without matching suppliers

  std::string query = R"(
    SELECT COALESCE(s.name, '') AS supplier_name, p.name AS product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT COALESCE(s.name, '') AS supplier_name, p.name AS product_name
    FROM Product p
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Execute the query
  auto stmt = conn.prepare(query);
  auto result = stmt.execute();

  // Process results
  for (const auto& row : result) {
    SupProd sp;
    sp.supplier_name = row.template get<std::string>(0);

    // Check if product_name is NULL
    if (row.is_null(1)) {
      sp.product_name = std::nullopt;
    } else {
      sp.product_name = row.template get<std::string>(1);
    }

    results.push_back(sp);
  }

  return results;
}

}  // namespace full_join_suppliers_products

