    FROM Department d
    RIGHT JOIN Employee e ON d.department_id = e.department_id
  )");
  analysis.right_join_results = right_results;

  // Execute FULL OUTER JOIN
  auto full_results = db.query<JoinResult>(R"(
    SELECT d.department_name, e.first_name, e.last_name, e.salary
    FROM Department d
    FULL OUTER JOIN Employee e ON d.department_id = e.department_id
  )");
  analysis.full_join_results = full_results;

  return analysis;
