  std::string first_name;
  std::string last_name;
  double salary;
};

struct JoinResult {
  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  // Create database connection
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Drop existing tables if they exist
  conn.execute("DROP TABLE IF EXISTS Employee");
  conn.execute("DROP TABLE IF EXISTS Department");

  // Create Department table
  conn.execute(R"(
    CREATE TABLE Department (
      department_id INTEGER PRIMARY KEY,
      department_name VARCHAR(100) NOT NULL,
      location VARCHAR(100)
    )
  )");

  // Create Employee table
  conn.execute(R"(
    CREATE TABLE Employee (
      employee_id INTEGER PRIMARY KEY,
      department_id INTEGER,
      first_name VARCHAR(50) NOT NULL,
      last_name VARCHAR(50) NOT NULL,
      salary REAL NOT NULL,
      FOREIGN KEY (department_id) REFERENCES Department(department_id)
    )
  )");

  // Insert departments
  for (const auto& dept : depts) {
    auto insert_stmt = conn.prepare(
      "INSERT INTO Department (department_id, department_name, location) VALUES (?, ?, ?)"
    );
    insert_stmt.bind(0, dept.department_id.value);
    insert_stmt.bind(1, dept.department_name);
    insert_stmt.bind(2, dept.location);
    insert_stmt.execute();
  }

  // Insert employees
  for (const auto& emp : emps) {
    auto insert_stmt = conn.prepare(
      "INSERT INTO Employee (employee_id, department_id, first_name, last_name, salary) VALUES (?, ?, ?, ?, ?)"
    );
    insert_stmt.bind(0, emp.employee_id.value);
    insert_stmt.bind(1, emp.department_id);
    insert_stmt.bind(2, emp.first_name);
    insert_stmt.bind(3, emp.last_name);
    insert_stmt.bind(4, emp.salary);
    insert_stmt.execute();
  }

  JoinAnalysis analysis;

  // 1. INNER JOIN - employees with assigned departments
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      INNER JOIN Employee e ON d.department_id = e.department_id
    )");

    auto result_set = stmt.query();
    while (result_set.next()) {
      JoinResult result;
      result.department_name = result_set.get<std::string>(0);
      result.first_name = result_set.get<std::string>(1);
      result.last_name = result_set.get<std::string>(2);
      result.salary = result_set.get<double>(3);
      analysis.inner_join_results.push_back(result);
    }
  }

  // 2. LEFT JOIN - all employees (even without departments)
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
    )");

    auto result_set = stmt.query();
    while (result_set.next()) {
      JoinResult result;
      if (!result_set.is_null(0)) {
        result.department_name = result_set.get<std::string>(0);
      }
      if (!result_set.is_null(1)) {
        result.first_name = result_set.get<std::string>(1);
      }
      if (!result_set.is_null(2)) {
        result.last_name = result_set.get<std::string>(2);
      }
      if (!result_set.is_null(3)) {
        result.salary = result_set.get<double>(3);
      }
      analysis.left_join_results.push_back(result);
    }
  }

  // 3. RIGHT JOIN - all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, so we simulate it with LEFT JOIN (reversed tables)
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

    auto result_set = stmt.query();
    while (result_set.next()) {
      JoinResult result;
      if (!result_set.is_null(0)) {
        result.department_name = result_set.get<std::string>(0);
      }
      if (!result_set.is_null(1)) {
        result.first_name = result_set.get<std::string>(1);
      }
      if (!result_set.is_null(2)) {
        result.last_name = result_set.get<std::string>(2);
      }
      if (!result_set.is_null(3)) {
        result.salary = result_set.get<double>(3);
      }
      analysis.right_join_results.push_back(result);
    }
  }

  // 4. FULL JOIN - all employees and departments
  // SQLite doesn't support FULL OUTER JOIN, so we simulate it with UNION
  {
    auto stmt = conn.prepare(R"(
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Employee e
      LEFT JOIN Department d ON e.department_id = d.department_id
      UNION
      SELECT d.department_name, e.first_name, e.last_name, e.salary
      FROM Department d
      LEFT JOIN Employee e ON d.department_id = e.department_id
    )");

    auto result_set = stmt.query();
    while (result_set.next()) {
      JoinResult result;
      if (!result_set.is_null(0)) {
        result.department_name = result_set.get<std::string>(0);
      }
      if (!result_set.is_null(1)) {
        result.first_name = result_set.get<std::string>(1);
      }
      if (!result_set.is_null(2)) {
        result.last_name = result_set.get<std::string>(2);
      }
      if (!result_set.is_null(3)) {
        result.salary = result_set.get<double>(3);
      }
      analysis.full_join_results.push_back(result);
    }
  }

  return analysis;
}

}  // namespace analyze_department_employees

